UPDATE coaching.exercise SET
  name = 'Landmine Cossack Squat',
  description = 'Perform Landmine Cossack Squat as a landmine-based squat lateral pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.',
  card_summary = 'Landmine Cossack Squat is a landmine exercise for loaded lateral squat for adductor strength, hip mobility, and side-to-side control. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.',
  coach_language = 'Primary subrole: frontal_plane_lower_body_strength. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.',
  athlete_language = 'Own the position first, move the bar second, and stop before the shape changes.',
  movement_family = 'Two-Handed Strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'landmine_landmine_cossack_squat',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = 20,
  default_rest_seconds = 75,
  est_seconds_per_set = 30,
  movement_requirements = '{"primary_joint_actions":["hip_flexion_extension","knee_flexion_extension","ankle_dorsiflexion_control"],"primary_tissues":["hip","knee","core","ankle"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0,"grip_profile":{"type":"two_handed","attachment":"bare_sleeve_or_two_hand_hold","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb,
  coaching_execution = '{"movement_description":"shift side to side through a lateral squat while the landmine guides the load path","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve with both hands or use a two-hand handle; keep elbows under control.","Set feet at a squat stance with enough room for knees and hips to track cleanly."],"execution_steps":["Descend with control, keeping the bar close to the center line and knees tracking with feet.","Drive through the floor and finish tall without leaning into the sleeve.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Push the floor away.","Knee tracks over the foot."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Knee collapse or pelvis shift under load.","Depth chasing after bracing is lost."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["upper_body_accessory_strength","rotational_power_work","late_session_sustained_capacity_if_programmed"],"pairs_well_after":["general_temperature_raise","shoulder_scapular_prep","trunk_bracing_activation"],"good_for_sessions":["landmine_strength","rotational_power","upper_body_strength","team_strength_circuit_with_quality_gates"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["no_safe_landmine_anchor","pain_in_target_pattern","athlete_cannot_control_bar_arc","session_goal_is_metabolic_exhaustion"]}'::jsonb,
