-- Landmine Rotational Press (landmine-rotational-press)
UPDATE coaching.exercise SET
  name = 'Landmine Rotational Press',
  description = 'Perform Landmine Rotational Press as a landmine-based rotate push pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.',
  card_summary = 'Landmine Rotational Press is a landmine exercise for hip-to-shoulder rotational press that builds diagonal power-strength transfer. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.',
  coach_language = 'Primary subrole: jump_throw_explosive_power. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.',
  athlete_language = 'Own the position first, move the bar second, and stop before the shape changes.',
  movement_family = 'Rotational Power and Core',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'landmine_landmine_rotational_press',
  default_sets = 4,
  default_reps = 5,
  default_work_seconds = 20,
  default_rest_seconds = 90,
  est_seconds_per_set = 30,
  movement_requirements = '{"primary_joint_actions":["shoulder_flexion","scapular_upward_rotation","elbow_extension","trunk_bracing","hip_rotation","thoracic_rotation","foot_pivot"],"primary_tissues":["core","shoulder","hip","upper_body","spine"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"moderate_bracing_with_controlled_exhale","balance_demand":"dynamic","coordination_demand":"high","impact_level":1,"grip_profile":{"type":"two_handed","attachment":"bare_sleeve_or_two_hand_hold","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb,
  coaching_execution = '{"movement_description":"rotate from the hips and trunk, then press through the landmine arc without twisting through the low back","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Hold the sleeve with both hands or use a two-hand handle; keep elbows under control.","Set an athletic stance with feet free to pivot and hips able to lead the rotation."],"execution_steps":["Press through the landmine arc while keeping ribs down and shoulder moving freely.","Finish with the arm long and the body stacked, then return under control.","Initiate rotation from the hips, pivot the feet, and let the trunk and press follow.","Control the return path instead of letting the bar pull the spine or shoulder.","Reset fully between reps so each rep is fast, crisp, and technically repeatable."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Press through the sleeve, not around it.","Reach long without rib flare.","Hips start it.","Pivot the feet.","Fast but connected."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Pressing only with the arm while the trunk leaks.","Rib flare at lockout.","Twisting through the low back instead of pivoting.","Locking the feet while forcing rotation."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["upper_body_accessory_strength","rotational_power_work","late_session_sustained_capacity_if_programmed"],"pairs_well_after":["general_temperature_raise","shoulder_scapular_prep","trunk_bracing_activation"],"good_for_sessions":["landmine_strength","rotational_power","upper_body_strength","team_strength_circuit_with_quality_gates"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["no_safe_landmine_anchor","pain_in_target_pattern","athlete_cannot_control_bar_arc","session_goal_is_metabolic_exhaustion"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["exercise_card_details_for_llm.md - Card v2 authoring requirements as described in accessible Vortex File Library outputs","Purpose.txt requested but not located in accessible File Library search results","Internal Vortex landmine demo recommended: front, side, and 45-degree views"],"internal_notes":["Film Landmine Rotational Press with a visible landmine anchor and clear bar arc.","Show setup, one slow rep, and two normal-speed quality reps.","Keep card language quality-first; do not frame as HIIT unless re-authored."]}'::jsonb,
  updated_at = now()
WHERE slug = 'landmine-rotational-press';

