-- Landmine Isometric Row Hold (landmine-isometric-row-hold)
UPDATE coaching.exercise SET
  name = 'Landmine Isometric Row Hold',
  description = 'Perform Landmine Isometric Row Hold as a landmine-based pull brace pattern. The athlete uses the fixed angled bar path to create useful load while maintaining bracing, breathing, grip ownership, and a repeatable finish position.',
  card_summary = 'Landmine Isometric Row Hold is a landmine exercise for isometric row position hold for scapular, grip, trunk, and hinge durability. Use it when the goal is quality force, posture, and repeatable bar path rather than fatigue chasing.',
  coach_language = 'Primary subrole: slow_eccentric_isometric_joint_resilience. Coach the athlete to earn load through setup, grip, stance, trunk pressure, and bar-path repeatability before chasing heavier plates or faster reps.',
  athlete_language = 'Own the position first, move the bar second, and stop before the shape changes.',
  movement_family = 'Rows and Pulls',
  primary_phase_key = 'resilience',
  phase_subrole = 'slow_eccentric_isometric_joint_resilience',
  primary_order_slot = 'landmine_landmine_isometric_row_hold',
  default_sets = 3,
  default_reps = 8,
  default_work_seconds = 25,
  default_rest_seconds = 45,
  est_seconds_per_set = 35,
  movement_requirements = '{"primary_joint_actions":["scapular_retraction_depression","shoulder_extension","elbow_flexion","hip_hinge_hold","anti_rotation","anti_extension","rib_pelvis_stack","grip_closure","wrist_neutral_control"],"primary_tissues":["core","forearm","upper_back","hand","hip"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"low_to_moderate_controlled_breathing","balance_demand":"moderate","coordination_demand":"high","impact_level":0,"grip_profile":{"type":"handle_grip","attachment":"neutral_handle_or_v_handle","wristRule":"neutral, pain-free wrist; choose ball or handle only when it improves control."}}'::jsonb,
  coaching_execution = '{"movement_description":"row or hold the landmine while resisting trunk twist, side bend, and grip collapse","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Attach the handle, V-handle, or neutral grip securely and confirm it matches the intended wrist position.","Hinge to the working height while keeping the spine long and the bar close enough to control."],"execution_steps":["Pull the sleeve or handle toward the target line while the shoulder blade moves cleanly.","Lower under control until the arm is long but the shoulder is not dumped forward.","Hold the bar in the target position and breathe without losing the rib-pelvis stack.","End the rep before the bar drifts, grip collapses, or the body twists.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Row with the back, not the neck.","Long arm down, strong shoulder back.","Grip organizes the shoulder.","Wrist neutral."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Yanking with the neck and upper trap.","Losing hinge position to finish the row.","Choosing an attachment that irritates the wrist or slips under load."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["upper_body_accessory_strength","rotational_power_work","late_session_sustained_capacity_if_programmed"],"pairs_well_after":["general_temperature_raise","shoulder_scapular_prep","trunk_bracing_activation"],"good_for_sessions":["landmine_strength","rotational_power","upper_body_strength","team_strength_circuit_with_quality_gates"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["no_safe_landmine_anchor","pain_in_target_pattern","athlete_cannot_control_bar_arc","session_goal_is_metabolic_exhaustion"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["exercise_card_details_for_llm.md - Card v2 authoring requirements as described in accessible Vortex File Library outputs","Purpose.txt requested but not located in accessible File Library search results","Internal Vortex landmine demo recommended: front, side, and 45-degree views"],"internal_notes":["Film Landmine Isometric Row Hold with a visible landmine anchor and clear bar arc.","Show setup, one slow rep, and two normal-speed quality reps.","Keep card language quality-first; do not frame as HIIT unless re-authored."]}'::jsonb,
  updated_at = now()
WHERE slug = 'landmine-isometric-row-hold';

