  movement_family = 'Ball-Grip and Handle-Grip Specialty',
  primary_phase_key = 'capacity',
  phase_subrole = 'hinge_posterior_chain_strength',
  primary_order_slot = 'landmine_landmine_handle_grip_deadlift',
  default_sets = 3,
  default_reps = 6,
  default_work_seconds = 20,
  default_rest_seconds = 75,
  est_seconds_per_set = 30,
