  coaching_execution = '{"movement_description":"hinge around the hips while the landmine load stays close and the spine remains organized","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Attach the handle, V-handle, or neutral grip securely and confirm it matches the intended wrist position.","Hinge to the working height while keeping the spine long and the bar close enough to control."],"execution_steps":["Push hips back, keep lats and trunk engaged, and stop before spinal position changes.","Extend through the hips rather than pulling the bar with the low back.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Hips back, ribs down.","Feel hamstrings before load.","Grip organizes the shoulder.","Wrist neutral."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Choosing an attachment that irritates the wrist or slips under load."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["upper_body_accessory_strength","rotational_power_work","late_session_sustained_capacity_if_programmed"],"pairs_well_after":["general_temperature_raise","shoulder_scapular_prep","trunk_bracing_activation"],"good_for_sessions":["landmine_strength","rotational_power","upper_body_strength","team_strength_circuit_with_quality_gates"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["no_safe_landmine_anchor","pain_in_target_pattern","athlete_cannot_control_bar_arc","session_goal_is_metabolic_exhaustion"]}'::jsonb,
