  coaching_execution = '{"movement_description":"row the landmine while allowing controlled hip rotation without losing trunk stiffness","setup":["Anchor the bar in a secure landmine base or immovable corner that cannot slide.","Load the bar conservatively and make sure the sleeve path is clear.","Attach the handle, V-handle, or neutral grip securely and confirm it matches the intended wrist position.","Hinge to the working height while keeping the spine long and the bar close enough to control."],"execution_steps":["Pull the sleeve or handle toward the target line while the shoulder blade moves cleanly.","Lower under control until the arm is long but the shoulder is not dumped forward.","Initiate rotation from the hips, pivot the feet, and let the trunk and press follow.","Control the return path instead of letting the bar pull the spine or shoulder.","Continue only while every rep matches the first clean rep."],"coach_cues":["Own the arc.","Brace before you move.","Stop before the shape changes.","Row with the back, not the neck.","Long arm down, strong shoulder back.","Hips start it.","Pivot the feet.","Rotate through the hips, not the low back."],"common_faults":["Using too much load before owning the bar path.","Letting the bar drift or bounce at the end range.","Holding breath so hard that posture or pressure changes.","Yanking with the neck and upper trap.","Losing hinge position to finish the row.","Twisting through the low back instead of pivoting.","Locking the feet while forcing rotation.","Choosing an attachment that irritates the wrist or slips under load."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["upper_body_accessory_strength","rotational_power_work","late_session_sustained_capacity_if_programmed"],"pairs_well_after":["general_temperature_raise","shoulder_scapular_prep","trunk_bracing_activation"],"good_for_sessions":["landmine_strength","rotational_power","upper_body_strength","team_strength_circuit_with_quality_gates"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["no_safe_landmine_anchor","pain_in_target_pattern","athlete_cannot_control_bar_arc","session_goal_is_metabolic_exhaustion"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["exercise_card_details_for_llm.md - Card v2 authoring requirements as described in accessible Vortex File Library outputs","Purpose.txt requested but not located in accessible File Library search results","Internal Vortex landmine demo recommended: front, side, and 45-degree views"],"internal_notes":["Film Landmine Handle-Grip Rotational Row with a visible landmine anchor and clear bar arc.","Show setup, one slow rep, and two normal-speed quality reps.","Keep card language quality-first; do not frame as HIIT unless re-authored."]}'::jsonb,
