-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Landmine patterns build force, trunk control, and repeatable bar-path ownership when dosed for the tagged phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('half-kneeling-one-arm-landmine-press', 'The landmine gives Half-Kneeling One-Arm Landmine Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is shoulder-friendly unilateral press with trunk and pelvis control. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('tall-kneeling-one-arm-landmine-press', 'The landmine gives Tall-Kneeling One-Arm Landmine Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is overhead-ish press that removes leg drive and exposes rib flare. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('split-stance-one-arm-landmine-press', 'The landmine gives Split-Stance One-Arm Landmine Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is staggered-stance press for trunk stiffness and hip-to-hand force transfer. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('square-stance-one-arm-landmine-press', 'The landmine gives Square-Stance One-Arm Landmine Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is general one-arm landmine press with simple athletic stance bracing. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('one-arm-landmine-push-press', 'The landmine gives One-Arm Landmine Push Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in output because the main training stress is leg-drive assisted press for rate of force expression through the landmine arc. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('one-arm-landmine-split-jerk', 'The landmine gives One-Arm Landmine Split Jerk a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in output because the main training stress is catch-under power press for advanced athletes with strong landing control. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('one-arm-landmine-floor-press', 'The landmine gives One-Arm Landmine Floor Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is floor-supported press that builds lockout and shoulder control with reduced lower-body demand. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('one-arm-landmine-z-press', 'The landmine gives One-Arm Landmine Z-Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is seated press that makes trunk posture, hamstring tolerance, and scapular control visible. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('one-arm-landmine-arc-press', 'The landmine gives One-Arm Landmine Arc Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in capacity because the main training stress is controlled diagonal press that teaches the shoulder to follow the landmine arc. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
  ('one-arm-eccentric-landmine-press', 'The landmine gives One-Arm Eccentric Landmine Press a constrained arc, reducing some degrees of freedom while still demanding bracing, grip, shoulder control, and lower-body contribution. This makes the drill easier to coach than many free-bar alternatives while still creating a meaningful strength or power problem.', 'Belongs in resilience because the main training stress is slow lowering press for shoulder, elbow, and trunk control under manageable load. Keep the phase honest: use low volume and full recovery for Output, progressive load for Capacity, and calm control for Resilience.', 'Place after Prepare & Access and any needed Movement Intelligence. Output variants come before heavy strength or conditioning; Capacity and Resilience variants belong in the main strength or accessory block before late-session fatigue work.', 'Common mistakes are overloading the sleeve, rushing the eccentric, twisting through the low back instead of pivoting, letting the bar drift off its arc, and turning the drill into a conditioning station.', 'Scale by load, range, stance width, kneeling vs standing position, tempo, attachment choice, rep speed, and rest. Progress only when the athlete can keep the same bar path and breathing under every rep.'),
